begin;create table if not exists public.ai_guardrail_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,user_id uuid references public.profiles(id)on delete set null,feature text not null,stage text not null check(stage in('input','output')),risk_level text not null check(risk_level in('low','medium','high')),blocked boolean not null,human_review_required boolean not null,finding_codes text[] not null default'{}',provider text,model text,created_at timestamptz not null default now());create index if not exists ai_guardrail_events_org_idx on public.ai_guardrail_events(organization_id,created_at desc);alter table public.ai_guardrail_events enable row level security;drop policy if exists ai_guardrail_events_management on public.ai_guardrail_events;create policy ai_guardrail_events_management on public.ai_guardrail_events for select to authenticated using(organization_id=(select public.current_organization_id())and(select coalesce(commercial_role,case role when'admin'then'director'else role end)from public.profiles where id=auth.uid())in('director','superintendent'));revoke all on public.ai_guardrail_events from anon,authenticated;grant select on public.ai_guardrail_events to authenticated;grant all on public.ai_guardrail_events to service_role;commit;
